const o="/api";function r(e){return fetch(`${o}/lines`,{headers:{Authorization:`Bearer ${e}`}}).then(n=>n.json())}function a(e,n){return fetch(`${o}/lines`,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${e}`},body:JSON.stringify(n)}).then(t=>t.json())}function s(e,n,t){return fetch(`${o}/lines/${encodeURIComponent(n)}`,{method:"PUT",headers:{"Content-Type":"application/json",Authorization:`Bearer ${e}`},body:JSON.stringify(t)}).then(i=>i.json())}export{a as c,r as g,s as u};
